		// Keep a few generic statements available for expressions whose data
		// dependency is hidden behind a path or an otherwise opaque node.
		for (Statement statement : pool.genericStatements()) {
			if (result.size() >= options.getMaxGeneratedStatements()) {
				break;
			}
			result.add(statement);
		}
		return new ArrayList<>(result);
